var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"무슨 일이야, 사장님.","JPN":"社長、どうした？","ENG":"What is it, Boss?","TWN":"老闆，找我幹嘛？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"이 요란한 실내 장식은 또 뭐고……? 내 생일은 아직 멀었는데?","JPN":"この派手な飾りはまた何だ……？　俺の誕生日はまだなんだけど。","ENG":"What's with these fancy decorations...? It's far from my birthday.","TWN":"這些花俏的裝飾是怎麼回事……？我的生日又還沒到？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐? 종신계약?","JPN":"は？　終身契約？","ENG":"What? A lifetime contract?","TWN":"什麼？終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"하하, 미안하지만 홍차 폭탄이랑 상의하라고.","JPN":"はは、悪いけど紅茶爆弾と相談しろよ。","ENG":"Ha ha, I'm sorry, but you should talk to Tea Bomb about that.","TWN":"哈哈，抱歉，請你找紅茶炸彈談吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그런 건, 나 같이 말단 기관원이 결정할 문제는 아닌 것 같으니까 말이야.","JPN":"そんなものは、俺みたいな平機関員が決められる問題じゃなさそうだからな。","ENG":"That's not something a low-ranking agent like me can decide.","TWN":"這不是我這個基層機關人員可以決定的事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐? 기관원 업무를 겸하는 조건으로……. 이미 받아 뒀다고?","JPN":"は？　機関員の業務も兼ねて……すでに許可をもらった？","ENG":"Huh? You've... already got her signature with the condition that I work both jobs?","TWN":"什麼？條件是機關那邊的事也會兼著做……然後機關長同意？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"나 참, 좀 더 이 자리에 어울리는 녀석도 있을 텐데.","JPN":"ったく、もっとこの場にふさわしいやつもいるんじゃないか？","ENG":"Blimey, I'm sure you have others who are more suited for this position, no?","TWN":"真是的，應該有人比我更適合這個位置吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"꼭 내가 아니면 안 되는 일이라고?","JPN":"絶対俺じゃないとダメだって？","ENG":"It has to be me?","TWN":"非我不可？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……뭐, 됐어.","JPN":"……まぁ、いい。","ENG":"...Fine.","TWN":"……哀，那好吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그 깐깐한 홍차 폭탄이 허락했으면 다 그만한 이유가 있겠지.","JPN":"あの厳しい紅茶爆弾が許したんなら、それなりに理由があるんだろ。","ENG":"If that strict Tea Bomb gave her permission, there must be a good reason for it.","TWN":"既然那個刁鑽的紅茶炸彈會答應，那應該有她的道理吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"책임에는 항상 그 무게가 따르는 법이라고 모건 할배한테 배웠어.","JPN":"責任には常に重みがついて来るものだって、モーガンのジジイから教わった。","ENG":"Morgan told me that great responsibility comes with a heavy weight to bear.","TWN":"責任總是伴隨著重擔，這是摩根老頭教我的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러니 무언가 선택을 하기 전에는 그만한 각오가 필요하다는 것도 말이야.","JPN":"だから何かを選択する前には、それなりの覚悟が必要だったこともな。","ENG":"And that determination is required for making a choice.","TWN":"所以要先想清楚，才能做出決定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"뭐, 맡기로 한 이상, 그게 어떤 일이든 대충대충 할 생각은 없으니까 안심해.","JPN":"まあ、引き受けることにした以上、それがどんなことでも適当にやるつもりはないから安心しろ。","ENG":"Well, don't worry. As long as I'm tasked with the job, I'll take it seriously.","TWN":"總之，你放心，既然我已經答應你，無論是任何事我都不會馬虎行事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"좋아, 계약서를 줘.","JPN":"よし、契約書をくれ。","ENG":"Now, give me the contract.","TWN":"來吧，把合約我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그동안 사장님한테는 꽤 신세를 졌으니까, 이런 식으로 빚을 갚는 것도 나쁘지는 않겠지.","JPN":"これまで社長には結構お世話になったし、こんな風に恩を返すのも悪くないだろ。","ENG":"Since you've done a lot for me, I guess this is a decent way to repay you.","TWN":"這段時間欠老闆不少人情債，用這種方式還債好像也不錯。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래서? 내가 해야 할 일이 뭔데?","JPN":"で？　俺の仕事は何だ？","ENG":"So? What should I do?","TWN":"然後呢？你要我做什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};